import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  LineChart, Line, AreaChart, Area, PieChart, Pie, Cell 
} from 'recharts';

const COLORS = ['#000000', '#333333', '#666666', '#999999', '#CCCCCC'];

function Dashboard() {
  const [activeTab, setActiveTab] = useState('analytics');
  const [analytics, setAnalytics] = useState({ 
    salesPerRest: [], 
    topItems: [], 
    globalAvg: null,
    salesTrend: []
  });
  const [restaurants, setRestaurants] = useState([]);
  const [users, setUsers] = useState([]);

  const [newRest, setNewRest] = useState({ name: '', cuisine: '', staffName: '', staffEmail: '', staffPassword: '' });
  const [newUser, setNewUser] = useState({ name: '', email: '', password: '', role: 'user', address: '', phone: '', restaurant_id: '' });

  useEffect(() => {
    fetchAnalytics();
    fetchRestaurants();
    fetchUsers();
  }, []);

  const fetchAnalytics = async () => {
    try {
      const [salesRes, itemsRes, avgRes, trendRes] = await Promise.all([
        axios.get('http://localhost:3000/analytics/sales-per-restaurant'),
        axios.get('http://localhost:3000/analytics/most-ordered-items'),
        axios.get('http://localhost:3000/analytics/average-order-value'),
        axios.get('http://localhost:3000/analytics/sales-trend')
      ]);
      setAnalytics({ 
        salesPerRest: salesRes.data, 
        topItems: itemsRes.data, 
        globalAvg: avgRes.data,
        salesTrend: trendRes.data
      });
    } catch (err) { console.error(err); }
  };

  const fetchRestaurants = async () => {
    const res = await axios.get('http://localhost:3000/restaurants');
    setRestaurants(res.data);
  };

  const fetchUsers = async () => {
    const res = await axios.get('http://localhost:3000/users');
    setUsers(res.data);
  };

  const handleAddRestaurant = async (e) => {
    e.preventDefault();
    try {
      const restRes = await axios.post('http://localhost:3000/restaurants', {
        name: newRest.name,
        cuisine: newRest.cuisine
      });

      if (newRest.staffEmail && newRest.staffPassword) {
        await axios.post('http://localhost:3000/users/register', {
          name: newRest.staffName || `${newRest.name} Staff`,
          email: newRest.staffEmail,
          password: newRest.staffPassword,
          role: 'restaurant',
          restaurant_id: restRes.data._id,
          address: 'Cafeteria Location',
          phone: 'N/A'
        });
      }

      setNewRest({ name: '', cuisine: '', staffName: '', staffEmail: '', staffPassword: '' });
      fetchRestaurants();
      fetchUsers();
      alert("Cafeteria and Staff account created successfully!");
    } catch (err) {
      console.error(err);
      alert("Error creating cafeteria/staff");
    }
  };

  const handleAddUser = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:3000/users/register', newUser);
      setNewUser({ name: '', email: '', password: '', role: 'user', address: '', phone: '', restaurant_id: '' });
      fetchUsers();
      alert("User credentials registered!");
    } catch (err) {
      console.error(err);
      alert("Error registering user");
    }
  };

  const chartTheme = {
    fontFamily: 'inherit',
    fontSize: '12px',
    fontWeight: 'bold'
  };

  return (
    <div style={{ color: '#000' }}>
      <div style={{ display: 'flex', gap: '2px', marginBottom: '3rem', background: '#000', padding: '2px' }}>
        <button 
          style={{ 
            flex: 1, 
            padding: '1rem', 
            background: activeTab === 'analytics' ? '#fff' : '#000', 
            color: activeTab === 'analytics' ? '#000' : '#fff',
            border: 'none',
            fontWeight: 'bold',
            cursor: 'pointer',
            transition: '0.2s'
          }} 
          onClick={() => setActiveTab('analytics')}
        >
          PLATFORM ANALYTICS
        </button>
        <button 
          style={{ 
            flex: 1, 
            padding: '1rem', 
            background: activeTab === 'restaurants' ? '#fff' : '#000', 
            color: activeTab === 'restaurants' ? '#000' : '#fff',
            border: 'none',
            fontWeight: 'bold',
            cursor: 'pointer',
            transition: '0.2s'
          }} 
          onClick={() => setActiveTab('restaurants')}
        >
          MANAGE CAFETERIAS
        </button>
        <button 
          style={{ 
            flex: 1, 
            padding: '1rem', 
            background: activeTab === 'users' ? '#fff' : '#000', 
            color: activeTab === 'users' ? '#000' : '#fff',
            border: 'none',
            fontWeight: 'bold',
            cursor: 'pointer',
            transition: '0.2s'
          }} 
          onClick={() => setActiveTab('users')}
        >
          USER CREDENTIALS
        </button>
      </div>

      {activeTab === 'analytics' && (
        <div style={{ animation: 'fadeIn 0.5s' }}>
          <div className="analytics-grid" style={{ marginBottom: '3rem' }}>
            <div className="analytic-card" style={{ border: '2px solid #000', borderRadius: '0', boxShadow: 'none' }}>
              <p style={{ fontWeight: 'bold', letterSpacing: '2px' }}>AVG ORDER VALUE</p>
              <div className="value" style={{ color: '#000', fontSize: '3rem' }}>${analytics.globalAvg?.avgOrderValue.toFixed(2)}</div>
            </div>
            <div className="analytic-card" style={{ border: '2px solid #000', borderRadius: '0', boxShadow: 'none' }}>
              <p style={{ fontWeight: 'bold', letterSpacing: '2px' }}>TOTAL ORDERS (7D)</p>
              <div className="value" style={{ color: '#000', fontSize: '3rem' }}>
                {analytics.salesTrend.reduce((acc, curr) => acc + curr.orderCount, 0)}
              </div>
            </div>
          </div>

          <div style={{ marginBottom: '4rem' }}>
            <h3 style={{ borderLeft: '10px solid #000', paddingLeft: '1rem', textTransform: 'uppercase' }}>7-Day Sales Trend</h3>
            <div style={{ height: '300px', width: '100%', background: '#fff', padding: '1rem', border: '1px solid #eee' }}>
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={analytics.salesTrend}>
                  <defs>
                    <linearGradient id="colorSales" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#000" stopOpacity={0.3}/>
                      <stop offset="95%" stopColor="#000" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#eee" />
                  <XAxis dataKey="_id" axisLine={false} tickLine={false} tick={{fill: '#000', fontWeight: 'bold'}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#000', fontWeight: 'bold'}} />
                  <Tooltip contentStyle={{ borderRadius: '0', border: '2px solid #000' }} />
                  <Area type="monotone" dataKey="totalSales" stroke="#000" strokeWidth={3} fillOpacity={1} fill="url(#colorSales)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '3rem' }}>
            <div>
              <h3 style={{ borderLeft: '10px solid #000', paddingLeft: '1rem', textTransform: 'uppercase' }}>Sales by Cafeteria</h3>
              <div style={{ height: '300px', width: '100%', background: '#fff', padding: '1rem', border: '1px solid #eee' }}>
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={analytics.salesPerRest}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#eee" />
                    <XAxis dataKey="restaurantName" axisLine={false} tickLine={false} tick={{fill: '#000', fontWeight: 'bold'}} />
                    <YAxis axisLine={false} tickLine={false} tick={{fill: '#000', fontWeight: 'bold'}} />
                    <Tooltip contentStyle={{ borderRadius: '0', border: '2px solid #000' }} />
                    <Bar dataKey="totalSales" fill="#000" />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
            <div>
              <h3 style={{ borderLeft: '10px solid #000', paddingLeft: '1rem', textTransform: 'uppercase' }}>Top Items (Global)</h3>
              <div style={{ height: '300px', width: '100%', background: '#fff', padding: '1rem', border: '1px solid #eee' }}>
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={analytics.topItems}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="totalQuantity"
                      nameKey="_id"
                    >
                      {analytics.topItems.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip contentStyle={{ borderRadius: '0', border: '2px solid #000' }} />
                    <Legend verticalAlign="bottom" height={36}/>
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'restaurants' && (
        <div style={{ background: 'white', padding: '2rem', border: '2px solid #000' }}>
          <h2 style={{ textTransform: 'uppercase', fontWeight: '900', letterSpacing: '2px' }}>Add New Cafeteria</h2>
          <form onSubmit={handleAddRestaurant} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '2rem' }}>
            <div style={{ gridColumn: 'span 2', background: '#000', color: '#fff', padding: '0.5rem 1rem', fontWeight: 'bold' }}>CAFETERIA DETAILS</div>
            <input type="text" placeholder="CAFETERIA NAME" value={newRest.name} onChange={e => setNewRest({...newRest, name: e.target.value})} required className="input" style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />
            <input type="text" placeholder="CUISINE" value={newRest.cuisine} onChange={e => setNewRest({...newRest, cuisine: e.target.value})} required className="input" style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />

            <div style={{ gridColumn: 'span 2', background: '#000', color: '#fff', padding: '0.5rem 1rem', fontWeight: 'bold', marginTop: '1rem' }}>STAFF CREDENTIALS</div>
            <input type="text" placeholder="STAFF FULL NAME" value={newRest.staffName} onChange={e => setNewRest({...newRest, staffName: e.target.value})} className="input" style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />
            <input type="email" placeholder="STAFF EMAIL" value={newRest.staffEmail} onChange={e => setNewRest({...newRest, staffEmail: e.target.value})} className="input" style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />
            <input type="password" placeholder="STAFF PASSWORD" value={newRest.staffPassword} onChange={e => setNewRest({...newRest, staffPassword: e.target.value})} className="input" style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />

            <button type="submit" style={{ gridColumn: 'span 2', marginTop: '1rem', background: '#000', color: '#fff', border: 'none', padding: '1.2rem', fontWeight: 'bold', cursor: 'pointer', textTransform: 'uppercase' }}>CREATE CAFETERIA & STAFF</button>
          </form>
          <hr style={{ border: '1px solid #000', margin: '2rem 0' }} />
          <h3 style={{ textTransform: 'uppercase' }}>Existing Cafeterias</h3>
          <div className="restaurant-grid">
            {restaurants.map(r => (
              <div key={r._id} className="card" style={{ padding: '1.5rem', borderRadius: '0', border: '2px solid #000', boxShadow: 'none' }}>
                <strong style={{ fontSize: '1.2rem' }}>{r.name.toUpperCase()}</strong>
                <div style={{ color: '#666', marginTop: '0.5rem' }}>{r.cuisine.toUpperCase()}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'users' && (
        <div style={{ background: 'white', padding: '2rem', border: '2px solid #000' }}>
          <h2 style={{ textTransform: 'uppercase', fontWeight: '900', letterSpacing: '2px' }}>Register Credentials</h2>
          <form onSubmit={handleAddUser} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '2rem' }}>
            <input type="text" placeholder="NAME" value={newUser.name} onChange={e => setNewUser({...newUser, name: e.target.value})} required style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />
            <input type="email" placeholder="EMAIL" value={newUser.email} onChange={e => setNewUser({...newUser, email: e.target.value})} required style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />
            <input type="password" placeholder="PASSWORD" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} required style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />
            <select value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value})} style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0', fontWeight: 'bold' }}>
              <option value="user">USER (STUDENT)</option>
              <option value="admin">ADMIN</option>
              <option value="restaurant">RESTAURANT STAFF</option>
            </select>

            {newUser.role === 'restaurant' && (
              <select 
                value={newUser.restaurant_id} 
                onChange={e => setNewUser({...newUser, restaurant_id: e.target.value})} 
                required 
                style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0', gridColumn: 'span 2', fontWeight: 'bold' }}
              >
                <option value="">SELECT CAFETERIA CONNECTION</option>
                {restaurants.map(r => (
                  <option key={r._id} value={r._id}>{r.name.toUpperCase()}</option>
                ))}
              </select>
            )}

            <input type="text" placeholder="ADDRESS" value={newUser.address} onChange={e => setNewUser({...newUser, address: e.target.value})} required style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />
            <input type="text" placeholder="PHONE" value={newUser.phone} onChange={e => setNewUser({...newUser, phone: e.target.value})} required style={{ padding: '1rem', border: '2px solid #000', borderRadius: '0' }} />
            <button type="submit" style={{ gridColumn: 'span 2', background: '#000', color: '#fff', border: 'none', padding: '1.2rem', fontWeight: 'bold', cursor: 'pointer', textTransform: 'uppercase' }}>REGISTER CREDENTIALS</button>
          </form>
          <hr style={{ border: '1px solid #000', margin: '2rem 0' }} />
          <h3 style={{ textTransform: 'uppercase' }}>Existing Credentials</h3>
          <table style={{ width: '100%', borderCollapse: 'collapse', border: '2px solid #000' }}>
            <thead>
              <tr style={{ background: '#000', color: '#fff' }}>
                <th style={{ textAlign: 'left', padding: '1rem' }}>NAME</th>
                <th style={{ textAlign: 'left', padding: '1rem' }}>EMAIL</th>
                <th style={{ textAlign: 'left', padding: '1rem' }}>ROLE</th>
                <th style={{ textAlign: 'left', padding: '1rem' }}>CONNECTION</th>
              </tr>
            </thead>
            <tbody>{users.map(u => (
              <tr key={u._id} style={{ borderBottom: '1px solid #000' }}>
                <td style={{ padding: '1rem' }}>{u.name.toUpperCase()}</td>
                <td style={{ padding: '1rem' }}>{u.email}</td>
                <td style={{ padding: '1rem' }}><span style={{ padding: '0.2rem 0.5rem', background: '#eee', fontWeight: 'bold' }}>{u.role.toUpperCase()}</span></td>
                <td style={{ padding: '1rem' }}>{u.role === 'restaurant' ? (restaurants.find(r => r._id === u.restaurant_id)?.name.toUpperCase() || 'LINKED') : 'N/A'}</td>
              </tr>
            ))}</tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default Dashboard;
